from pynput import keyboard

def on_press(key):
    try:
        if key.char == 'u':
            print('Up')
        elif key.char == 'd':
            print('Down')
        elif key.char == 'l':
            print('Left')
        elif key.char == 'r':
            print('Right')
        else:
            print(key)
    except AttributeError:
        pass

def on_release(key):
    if key == keyboard.Key.esc:
        # Stop listener
        return False

# Collect events until released
with keyboard.Listener(on_press=on_press, on_release=on_release) as listener:
    listener.join()

# Run forever
